// Parse the form inputs into arrays
const jobRoles = $input.first().json['Job Roles']
  .split(',')
  .map(r => r.trim())
  .filter(r => r.length > 0);

const locations = $input.first().json['Locations']
  .split(',')
  .map(l => l.trim())
  .filter(l => l.length > 0);

const maxResults = parseInt($input.first().json['Max Results Per Search']) || 10;
const postedSince = $input.first().json['Posted Since'] || '1 week';

// Create search combinations
const searches = [];
for (const role of jobRoles) {
  for (const location of locations) {
    searches.push({
      job_role: role,
      location: location,
      max_results: maxResults,
      posted_since: postedSince
    });
  }
}

return searches.map(s => ({ json: s }));

// Flatten all job results and add unique IDs
const jobs = $input.all().flatMap(item => {
  if (Array.isArray(item.json)) {
    return item.json;
  }
  return [item.json];
});

// Add unique IDs and search context
const searchContext = $('Loop Over Search Batches').item.json;

// Simple hash function for deduplication
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit integer
  }
  return Math.abs(hash).toString(36);
}

return jobs.map((job, idx) => {
  // Create deterministic hash from job_url or company+title+location
  const hashInput = (job.job_url || `${job.company_name || ''}|${job.job_title || job.designation || ''}|${job.job_location || job.location || ''}`).toLowerCase().trim();
  const job_hash = simpleHash(hashInput) + '-' + simpleHash(hashInput.split('').reverse().join(''));

  return {
    json: {
      unique_id: `${Date.now()}-${idx}-${Math.random().toString(36).substr(2, 9)}`,
      job_hash: job_hash,
      lead_source: 'job_board',
      search_role: searchContext.job_role,
      search_location: searchContext.location,
      ...job
    }
  };
});

// Get flattened jobs and existing sheet data
const flattenedJobs = $('Flatten Job Results and ID').all();
const existingRows = $('Read Jobs from Sheets').all();

// Build set of existing job hashes
const existingHashes = new Set();
for (const row of existingRows) {
  if (row.json.job_hash) {
    existingHashes.add(row.json.job_hash);
  }
}

// Filter out duplicates
const uniqueJobs = flattenedJobs.filter(job => {
  return !existingHashes.has(job.json.job_hash);
});

// If no new unique jobs, return empty array (pipeline stops naturally)
if (uniqueJobs.length === 0) {
  return [];
}

return uniqueJobs;

const job_d = $('Loop Over Job Batches').item.json;
const raw = $input.first().json;

// ðŸ”¥ GET COMPANY FROM JOB DATA
let savedJob = {};
// Company data comes from job_d

// ðŸ”¥ PRIORITY LOGIC
// 1. job_d.company_name
// 2. fallback ''
const company_name = job_d?.company_name || '';

// ðŸ”¥ PARSE AI RESPONSE
let parsed = {};

if (raw?.output?.[0]?.content?.[0]?.text) {
  const text = raw.output[0].content[0].text;

  if (typeof text === 'object') {
    parsed = text;
  } else if (typeof text === 'string') {
    try {
      parsed = JSON.parse(text);
    } catch (e) {
      parsed = {};
    }
  }
}

// fallback
if (!parsed || Object.keys(parsed).length === 0) {
  parsed = {
    lead_score: 0,
    decision: 'REJECT',
    reason: 'Parse error',
    industry: 'Other',
    country: 'Unknown'
  };
}

// âœ… FINAL OUTPUT
return [{
  json: {
    ...job_d,

    // ðŸ”¥ FIXED COMPANY NAME
    company_name,

    // debug (remove later)
    company_source: job_d?.company_name ? 'job_data' : 'missing',

    lead_score: parsed.lead_score ?? 0,
    decision: parsed.decision ?? 'REJECT',
    reason: parsed.reason ?? '',
    industry: parsed.industry ?? 'Other',
    country: parsed.country ?? 'Unknown'
  }
}];
